class Somersd:
    def time_somersd(self, n_size):
        res = stats.somersd(self.x, self.y)

    def setup(self, n_size):
        rng = np.random.default_rng(12345678)
        self.x = rng.choice(n_size, size=n_size)
        self.y = rng.choice(n_size, size=n_size)
